                    pauseRollUrl: defaults.premiumFlag ? '' : flashvars.pauseroll_url,
                    htmlPauseRoll : defaults.premiumFlag ? 'false' : 'true',
                    htmlPostRoll  : defaults.premiumFlag ? 'false' : 'true',
                    extraFlashvars: {
                        oldFlash: {
                            hidePostPauseRoll: defaults.premiumFlag
                        },
